var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"오퍼레이션 <color=#ffd34c>클리포트 게임</color> 최종국면        \\n관리국 제 1 강습전대 『<color=#ffd34c>FENRIR</color>』        \\nCSE Lv. 5        ","JPN":"オペレーション<color=#ffd34c>クリフォトゲーム</color>最終局面        \\n管理局 第1強襲戦隊『<color=#ffd34c>FENRIR</color>』        \\nCSE Lv. 5        ","ENG":"Operation; <color=#ffd34c>Qliphoth Game</color> Final Phase        \\nAdministration 1 Assault Division 『<color=#ffd34c>Fenrir</color>』        \\nCSE Lv. 5        ","TWN":"操作 <color=#ffd34c>遊戲埠</color> 最終局面 \\n管理局第一強襲部隊『<color=#ffd34c>Fenrir</color>』 \\nCSE Lv. 5"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_SL_NULL_ADMINOPERATOR","text":{"KOREA":"여기는 관리국 제 1 강습전대 펜릴!","JPN":"こちら管理局第1強襲戦隊フェンリル！","ENG":"This is Administration 1st Assault Division Fenrir!","TWN":"這裡是管理局第1強襲戰隊的芬里爾！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_SL_NULL_ADMINOPERATOR","text":{"KOREA":"생존 부대는 응답하라!","JPN":"生存部隊は応答せよ！","ENG":"Requesting confirmation from any surviving units!","TWN":"存活部隊請回答！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_SL_NULL_ADMINOPERATOR","text":{"KOREA":"반복한다! 여기는 관리국 제 1 강습전대 펜릴!","JPN":"繰り返す！　こちら管理局第1強襲戦隊フェンリル！","ENG":"I repeat! This is Administration 1st Assault Division Fenrir!","TWN":"重複一遍！這裡是管理局第1強襲戰隊的芬里爾！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_SL_NULL_ADMINOPERATOR","text":{"KOREA":"즉시 증원이 필요하다! 생존 부대는 응답하라!","JPN":"大至急増援を求む！　生存部隊は応答せよ！","ENG":"Requesting reinforcements immediately! All surviving units, come in!","TWN":"這裡急需增援！存活部隊請回答！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......아무래도 도와줄 형편이 되는 곳은 없는 모양이네요.","JPN":"……手を貸す余裕のあるところなんてないようですね。","ENG":"...Even if anyone's still alive, I doubt they're in any position to help.","TWN":"……好像怎麼樣都不會有增援了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"상황 최악인데요?","JPN":"これって最悪の状況なんじゃないですか？","ENG":"This can't get any worse...","TWN":"這是最糟糕的狀況了吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"흥! 그런 약골들, 와 봤자 도움도 안 돼!","JPN":"フン！　あんな奴ら、どうせ役立たずだよ！","ENG":"Hmph! Those wimps aren't gonna be much help anyway!","TWN":"哼！那群廢物就算來了也幫不上忙！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이 정도 역경 따위,","JPN":"これしきの逆境なんか、","ENG":"No big deal.","TWN":"這種程度的困境，"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"나랑 스승님만 계시면 아무것도 아니라고!","JPN":"私と師匠さえいれば何でもないんだから！","ENG":"As long as Master and I are here, it'll be a piece of cake!","TWN":"只要有我和師父在，根本不算什麼！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그렇죠, 스승님?","JPN":"そうですよね、師匠？","ENG":"Right, Master?","TWN":"對吧，師父？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"........","JPN":"……","ENG":"........","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"부대 상황은?","JPN":"部隊の状況は？","ENG":"What's the SITREP?","TWN":"部隊的情況如何？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"가용 전투력은 평시의 60% 이하......","JPN":"動ける戦力は平常時の60％以下……","ENG":"Percentage-wise, less than 60% of our forces remain mission capable.","TWN":"部隊的戰力不到平日的60%……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"강습함 글레입니르는 화기관제 시스템이 손상되어 보조 전투 정도만 가능한 상황입니다.","JPN":"強襲艦グレイプニルは火器管制システムが損傷し、補助戦闘のみ可能な状況です。","ENG":"And with Assault Ship Gleipnir's fire control system damaged, we can expect only limited fire support.","TWN":"強襲戰艦·格萊伊尼勒的火控系統受損，現在只能作戰鬥輔助。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......조금 힘들겠는데요, 이거.","JPN":"……これはちょっと厳しそうですね。","ENG":"That doesn't bode well...","TWN":"……有點棘手呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"힘들긴 뭐가 힘들어!","JPN":"弱音なんか吐かないで！","ENG":"Stop whining like a baby!","TWN":"這有什麼難的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"나랑 스승님만 계시면 우리 펜릴 강습전대는 언제나 최적! 만전! 최강의 상태라고!","JPN":"私がいて、師匠さえいてくれれば、我がフェンリル強襲戦隊はいつでも最適！　万全！　最強の状態だよ！","ENG":"As long as Master and I are here, Assault Division Fenrir is always in tip-top shape! Always ready to fight! No matter what!","TWN":"只要有我和師父在，芬里爾強襲部隊就是最佳！最完美！而且最強！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그렇죠, 스승님?","JPN":"そうですよね、師匠？","ENG":"Right, Master?","TWN":"對吧，師父？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"넌 참 좋겠다. 항상 아드레날린이 펑펑 솟아나서.","JPN":"君が羨ましいよ。いつもアドレナリン全開だから。","ENG":"I must say, I envy you. Always pumped full of adrenaline.","TWN":"真羡慕妳啊，腎上腺素永遠都分泌得這麼旺盛。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"평생 저혈압 걱정은 없겠네.","JPN":"低血圧になる心配なんて一生なさそうだ。","ENG":"I bet you save a lot of money on energy drinks.","TWN":"看來妳一輩子都不用擔心會低血壓呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 너 지금 뭐라 그랬어?!","JPN":"何ですって？　もういっぺん言ってみなさい！！","ENG":"Huh? What did you just say?!","TWN":"什麼？你說什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그녀는?","JPN":"彼女は？","ENG":"What about her?","TWN":"她呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그녀는, 어떻게 됐지?","JPN":"彼女は、どうなった？","ENG":"Any updates?","TWN":"她，怎麼樣了？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그녀는...... 차원단층 폭파 직후부터 연락 두절입니다.","JPN":"彼女は……次元断層爆破の直後から通信が途絶えています。","ENG":"She... We lost contact after our troops detonated the dimensional fault.","TWN":"她……從次元斷層爆破後就失去了聯絡。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그녀를 구하러 가신다고 해도 이미......","JPN":"今から助けに向かったところで、すでに……","ENG":"I fear that she's already... I'm sorry.","TWN":"就算您要去救她，也已經……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"죄송합니다만, 대장님.","JPN":"お言葉ですが……隊長。","ENG":"With all due respect, Commander...","TWN":"抱歉，隊長。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"지금은 그녀에게 신경을 쓰실 때가 아닙니다.","JPN":"今は彼女の身を案じている場合ではありません。","ENG":"We can't exactly afford to worry about her at the moment.","TWN":"但現在可不是擔心她的時候，"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"이번 클리포트 게임은 아무리 봐도 정상이 아닙니다.","JPN":"このクリフォトゲームは、どう見ても普通じゃないんです。","ENG":"There's something undoubtedly extraordinary about this Qliphoth Game.","TWN":"這次的逆卡巴拉遊戲無論怎麼看都不太正常。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"관리국도 관리국이지만 놈들도 거의 한계 상황일 겁니다.","JPN":"管理局も管理局ですが、奴らもほとんど限界に近いでしょう。","ENG":"As formidable as the Administration may be, they're probably stretched thin by now as well.","TWN":"雖然不知道管理局是怎麼打算的，但這些傢伙們也差不多到極限了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"이런 의미 없는 소모전을 지속하면서 대체 뭘 노리고 있는 건지.......","JPN":"こんな無意味な消耗戦を繰り返してまで、いったい何を狙ってるのか……","ENG":"I can't help but question what they're after, insisting on continuing this meaningless war of attrition...","TWN":"一直持續進行這種消耗戰到底有什麼目的……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"......알겠다.","JPN":"……わかった。","ENG":"Understood.","TWN":"……我知道了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"일단 다른 일은 이곳을 빠져나간 후에 생각한다.","JPN":"以後の事は、ひとまずここを切り抜けてから考えるとしよう。","ENG":"We'll take care of other things when we get out of here.","TWN":"先想辦法出去，再想別的事情。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"나유빈, 작전을 제안하도록.","JPN":"イチノセ・カオル、お前の作戦を聞こう。","ENG":"Brief me on the plan, Yubin.","TWN":"羅瑜斌，制定作戰方案。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"우선 차원 도약 좌표를 교란하는 적 침식 쐐기들을 모두 파괴해야 합니다.","JPN":"まずは次元跳躍座標を撹乱させている、敵の侵食くさびをすべて破壊すべきです。","ENG":"We have to destroy all the Corrupted Wedges of enemies that are interfering with the Dimension Jump coordinates.","TWN":"首先，我們必須破壞掉干擾次元躍遷座標的侵蝕釘才行。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그런 후에 한시라도 빨리 이곳을 벗어나 본대와 합류해야 합니다.","JPN":"その後、一刻も早くここを抜け出し、本体と合流しなければなりません。","ENG":"Afterward, we must find our way out of here and join the main effort as soon possible.","TWN":"然後儘快從這裡脫身，與本隊會合。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간단하네! 다 때려 부수면 된단 뜻이잖아?","JPN":"簡単だね！　全部ブッ壊せばいいってことでしょ？","ENG":"That's simple! We just have to wipe them all out, right?","TWN":"還不簡單！把它們全部打爆就好了，對吧?"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 쉬운 일이 아니야. 아직 살아 있는 침식체들이 다 저기에 몰려 있다고.","JPN":"言うほど簡単なことじゃないさ。まだ生きている侵食体があそこに集まっているんだから。","ENG":"It's not that easy. All the Corrupted Objects that are still alive are gathered over there.","TWN":"並沒有那麼簡單，因為它們會把存活的侵蝕體聚集到自己那裡。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마, 이 겁쟁아.","JPN":"大丈夫だよ、この弱虫。","ENG":"Don't worry. You're such a coward!","TWN":"不用你擔心，膽小鬼。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님과 이 몸이 나서면 낙승, 또 낙승이라고!","JPN":"師匠とこの私が出れば、楽勝に次ぐ楽勝なんだから！","ENG":"As long as Master and I are here, it'll be easy peasy!","TWN":"只要有我和師父出馬，就是輕鬆獲勝再獲勝！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"하아...... 그래.","JPN":"はあ……そう。","ENG":"*Sigh* Sure.","TWN":"唉……是嗎。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그럼 결정됐군.","JPN":"では決まりだな。","ENG":"So it's decided.","TWN":"那就這麼決定了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"나와 펜릴 전대가 침식 쐐기들을 파괴하러 간다.","JPN":"私とフェンリル戦隊が侵食くさびを破壊しに向かう。","ENG":"The Fenrir Division and I will go destroy the Corrupted Wedges.","TWN":"我和芬里爾戰隊去破壞那些侵蝕釘。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"함내 승무원들은 침식 쐐기가 파괴되는 즉시 차원 도약으로 빠져나갈 수 있게 준비하도록.","JPN":"艦内の乗組員は、侵食くさびが破壊され次第、次元跳躍で抜け出せるよう準備をしておくように。","ENG":"The rest of the crew are to standby, ready to make the jump as soon as the Corrupted Wedges are destroyed.","TWN":"艦上的機組人員們準備好，侵蝕釘一被破壞就馬上開始次元躍遷。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"이상!","JPN":"以上だ！","ENG":"Go!","TWN":"over！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};